//for css    :root  { filter: brightness(1); --zero: rgba(000, 000, 000, 0.0); --first: rgba( 057,120,121,1); --second:rgba(158, 187 ,22, 1.0); --third:rgba(155, 155, 155, 1.0); --fourth: rgba(055,055,055, 1); --fifth: rgba(255, 000, 000, 0.3); --sixth: #9EBB1633; background: var(--sixth); }

//document.getElementsByTagName("text")[0].textContent = ".dog";
const path = document.getElementsByTagName("circle")[0];
const bbox = path.getBBox();

const cX = bbox.x + bbox.width / 2;
const cY = bbox.y + bbox.height / 2;
//Center: 
//console.log("Center:", cX, cY, bbox.width, bbox.height);
path.setAttribute("transform", `translate(${cX}, ${cY}) scale(0.5) translate(${-cX}, ${-cY})`);
